import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is a square root?", a: "A square root of a number is a value that, when multiplied by itself, equals the original number. For example, the square root of 49 is 7 because 7 x 7 = 49." },
  { q: "How do you calculate a cube root?", a: "A cube root is the number that must be multiplied by itself three times to reach the original value. For example, the cube root of 27 is 3 because 3 x 3 x 3 = 27." },
  { q: "What is an nth root?", a: "An nth root is a value that produces the original number when raised to the nth power. For example, the fourth root of 16 is 2 because 2^4 = 16." },
  { q: "How do you simplify square roots?", a: "Factor the number and pull out perfect-square factors. For example, sqrt(72) = sqrt(36 x 2) = 6sqrt(2)." },
  { q: "What is the square root of a negative number?", a: "The square root of a negative number is not real. It is complex and uses i, where i- = -1. For example, sqrt(-9) = 3i." },
];

type Mode = "root" | "power";
const fmt = (value: number) => Number.isFinite(value) ? Number(value.toFixed(8)).toLocaleString() : "Invalid";

export default function RootCalculator() {
  const [mode, setMode] = useState<Mode>("root");
  const [value, setValue] = useState(81);
  const [index, setIndex] = useState(2);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  const result = useMemo(() => {
    if (index === 0) return { label: "Invalid index", value: "Index cannot be zero", step: "Root index and power must not be zero." };
    if (mode === "power") {
      const power = Math.pow(value, index);
      return { label: `${index}th Power`, value: fmt(power), step: `${value}^${index} = ${fmt(power)}.` };
    }
    const oddIndex = Math.abs(Math.round(index)) % 2 === 1;
    if (value < 0 && !oddIndex) {
      const magnitude = Math.pow(Math.abs(value), 1 / index);
      return { label: `${index}th Root`, value: `${fmt(magnitude)}i`, step: `Because ${value} is negative and ${index} is even, the real root is not defined. Complex result = ${fmt(magnitude)}i.` };
    }
    const root = value < 0 ? -Math.pow(Math.abs(value), 1 / index) : Math.pow(value, 1 / index);
    return { label: `${index}th Root`, value: fmt(root), step: `${index}th root of ${value} = ${value}^(1/${index}) = ${fmt(root)}. Check: ${fmt(root)}^${index} - ${fmt(Math.pow(root, index))}.` };
  }, [mode, value, index]);

  return (
    <>
      <SEOHead title="Free Root Calculator Online - Calculate Square Root Cube Root and Nth Root Instantly | CalcHive" description="Free online root calculator. Calculate square root, cube root and any nth root of any number instantly with step by step solution. 100% free for students and everyone, no signup required." canonical="/root-calculator" keywords="free root calculator, square root calculator free online, cube root calculator free, nth root calculator free, calculate square root free online" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Root Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free root calculator to calculate square root free online, cube root, nth root, and inverse powers.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
            <div><label htmlFor="mode" className="text-sm font-semibold text-foreground block mb-2">Mode</label><select id="mode" value={mode} onChange={(event) => setMode(event.target.value as Mode)} className={inputClass}><option value="root">Root</option><option value="power">Inverse power</option></select></div>
            <div><label htmlFor="value" className="text-sm font-semibold text-foreground block mb-2">Number</label><input id="value" type="number" inputMode="decimal" value={value} onChange={(event) => setValue(Number(event.target.value))} className={inputClass} /></div>
            <div><label htmlFor="index" className="text-sm font-semibold text-foreground block mb-2">{mode === "root" ? "Root index" : "Power"}</label><input id="index" type="number" inputMode="decimal" value={index} onChange={(event) => setIndex(Number(event.target.value))} className={inputClass} /></div>
          </div>
          <motion.div key={`${mode}-${value}-${index}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{result.label}</p><p className="text-6xl font-black text-white tracking-tight break-words" data-testid="result-root">{result.value}</p></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Square Root Cube Root and Nth Root for Free</h2><p className="text-muted-foreground leading-relaxed">Enter a number and root index. This square root calculator free online also works as a cube root calculator free and nth root calculator free.</p><h2 className="text-2xl font-bold text-foreground">How to Find the Root of Any Number</h2><p className="text-muted-foreground leading-relaxed">An nth root is the same as raising a number to the power of 1/n. The inverse mode raises a number back to a selected power.</p><h2 className="text-2xl font-bold text-foreground">Free Math Root Tool for Students and Everyone</h2><p className="text-muted-foreground leading-relaxed">Use this calculate square root free online tool for algebra, geometry, powers, and complex-number checks.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/root-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


